import { Component, OnDestroy, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, ReactiveFormsModule } from '@angular/forms';
import { Subject, combineLatest, startWith, takeUntil } from 'rxjs';
import { StockItem } from '../../models/stock-item';
import { StockStoreService } from '../../services/stock-store.service';

interface StockGroup {
  category: string;
  items: StockItem[];
}

@Component({
  selector: 'app-stock',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './stock.component.html',
  styleUrls: ['./stock.component.css']
})
export class StockComponent implements OnInit, OnDestroy {
  private readonly destroy$ = new Subject<void>();

  filters = this.fb.group({
    search: [''],
    category: ['all'],
    color: ['all']
  });

  groupedItems: StockGroup[] = [];
  totalItems = 0;
  alertItems = 0;
  categories: string[] = [];

  constructor(private fb: FormBuilder, private store: StockStoreService) {}

  async ngOnInit(): Promise<void> {
    // ✅ important : attendre le seed/chargement pour éviter un écran vide au début
    await this.store.load();

    // ✅ liste des catégories (triée)
    this.store.items$
      .pipe(takeUntil(this.destroy$))
      .subscribe((items) => {
        this.categories = Array.from(new Set(items.map((i) => i.category))).sort((a, b) =>
          a.localeCompare(b)
        );
      });

    // ✅ filtre + regroupement
    combineLatest([
      this.store.items$,
      this.filters.valueChanges.pipe(startWith(this.filters.getRawValue()))
    ])
      .pipe(takeUntil(this.destroy$))
      .subscribe(([items, filters]) => {
        const search = (filters.search ?? '').trim().toLowerCase();
        const category = filters.category ?? 'all';
        const color = filters.color ?? 'all';

        const filtered = items
          .filter((item) => {
            const matchesSearch = !search || item.reference.toLowerCase().includes(search);
            const matchesCategory = category === 'all' || item.category === category;
            const matchesColor = color === 'all' || item.color === color;
            return matchesSearch && matchesCategory && matchesColor;
          })
          // ✅ petit tri global (référence)
          .sort((a, b) => a.reference.localeCompare(b.reference));

        this.totalItems = filtered.length;
        this.alertItems = filtered.filter((i) => i.quantity <= i.lowStockThreshold).length;

        // ✅ regrouper + trier les groupes
        this.groupedItems = this.groupByCategory(filtered).sort((a, b) =>
          a.category.localeCompare(b.category)
        );
      });
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  trackById(_index: number, item: StockItem): string {
    return item.id;
  }

  async updateQuantity(item: StockItem, quantity: number): Promise<void> {
    const next = Math.max(0, Number.isFinite(quantity) ? Number(quantity) : 0);
    await this.store.setQuantity(item.id, next);
  }

  async changeQuantity(item: StockItem, delta: number): Promise<void> {
    const next = Math.max(0, Number(item.quantity) + delta);
    await this.store.setQuantity(item.id, next);
  }

  exportCsv(): void {
    const rows: string[] = [];
    rows.push('reference,category,color,unit,quantity,threshold,lastUpdated');

    this.groupedItems.forEach((group) => {
      group.items.forEach((item) => {
        const values = [
          item.reference,
          item.category,
          item.color,
          item.unit,
          String(item.quantity),
          String(item.lowStockThreshold),
          item.lastUpdated
        ];
        rows.push(values.map((v) => this.escapeCsv(v)).join(','));
      });
    });

    const csv = rows.join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = 'stock.csv';
    link.click();

    URL.revokeObjectURL(url);
  }

  private groupByCategory(items: StockItem[]): StockGroup[] {
    const map = new Map<string, StockItem[]>();

    for (const item of items) {
      const group = map.get(item.category);
      if (group) group.push(item);
      else map.set(item.category, [item]);
    }

    // ✅ items triés par référence dans chaque groupe
    return Array.from(map.entries()).map(([category, groupItems]) => ({
      category,
      items: groupItems.sort((a, b) => a.reference.localeCompare(b.reference))
    }));
  }

  private escapeCsv(value: string): string {
    const needsQuotes = value.includes(',') || value.includes('"') || value.includes('\n');
    const escaped = value.replace(/"/g, '""');
    return needsQuotes ? `"${escaped}"` : escaped;
  }
}
<section class="panel">
  <div class="panel-header">
    <div>
      <h1>Stock</h1>
      <p>Suivi en temps r&eacute;el des articles par famille.</p>
    </div>
    <div class="panel-actions no-print">
      <button class="btn outline" type="button" (click)="exportCsv()">Exporter CSV</button>
    </div>
  </div>

  <section class="card">
    <div class="filters" [formGroup]="filters">
      <label class="field">
        <span>Recherche</span>
        <input class="input" type="search" formControlName="search" placeholder="Reference produit">
      </label>
      <label class="field">
        <span>Famille</span>
        <select class="input" formControlName="category">
          <option value="all">Toutes</option>
          <option *ngFor="let cat of categories" [value]="cat">{{ cat }}</option>
        </select>
      </label>
      <label class="field">
        <span>Couleur</span>
        <select class="input" formControlName="color">
          <option value="all">Toutes</option>
          <option value="blanc">Blanc</option>
          <option value="gris">Gris</option>
          <option value="noir">Noir</option>
        </select>
      </label>
    </div>

    <div class="summary">
      <div>
        <span>Total articles</span>
        <strong>{{ totalItems }}</strong>
      </div>
      <div class="alert">
        <span>Articles en alerte</span>
        <strong>{{ alertItems }}</strong>
      </div>
    </div>
  </section>

  <section class="stock-groups">
    <div class="stock-group" *ngFor="let group of groupedItems">
      <div class="group-header">
        <h2>{{ group.category }}</h2>
        <span class="tag">{{ group.items.length }} articles</span>
      </div>

      <div class="stock-grid">
        <article
          class="stock-card"
          *ngFor="let item of group.items; trackBy: trackById"
          [class.low-stock]="item.quantity <= item.lowStockThreshold"
        >
          <div class="stock-image">
            <img [src]="item.photoUrl" alt="Stock item">
            <span class="badge" *ngIf="item.quantity <= item.lowStockThreshold">Rupture proche</span>
          </div>
          <div class="stock-info">
            <div class="stock-ref">{{ item.reference }}</div>
            <div class="stock-meta">
              <span>{{ item.color }}</span>
              <span>{{ item.unit }}</span>
            </div>
          </div>
          <div class="stock-actions">
            <button class="btn ghost" type="button" (click)="changeQuantity(item, -1)">-1</button>
            <input
              class="input qty"
              type="number"
              min="0"
              [value]="item.quantity"
              (change)="updateQuantity(item, $any($event.target).valueAsNumber)"
            >
            <button class="btn ghost" type="button" (click)="changeQuantity(item, 1)">+1</button>
          </div>
        </article>
      </div>
    </div>
  </section>
</section>
